 197	export const PreDefinedQueriesDropdown = () => {
 198	  const [activeNamespace] = useActiveNamespace();
 199	  const { perspective } = usePerspective();
 200	
 201	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 202	
 203	  const queries: SelectOptionProps[] = React.useMemo(() => {
 204	    switch (perspective) {
 205	      case 'dev':
 206	        return devQueries(activeNamespace);
 207	      case 'admin':
 208	      case 'virtualization-perspective':
 209	        return predefinedQueriesAdmin;
 210	      // TODO: Add ACM queries
 211	      default:
 212	        return [];
 213	    }
 214	  }, [activeNamespace, perspective]);
 215	
 216	  const dispatch = useDispatch();
 217	
 218	  const queriesList = useSelector((state: MonitoringState) =>
 219	    getLegacyObserveState(perspective, state)?.getIn(['queryBrowser', 'queries']),
 220	  );
 221	
 222	  const insertPredefinedQuery = (query: string) => {
 223	    const queriesListDetails = queriesList.toJS();
 224	    const isInitialQueryEmpty =
 225	      queriesList.size === 1 &&
 226	      (queriesListDetails[0]?.text === '' ||
 227	        queriesListDetails[0]?.text === null ||
 228	        queriesListDetails[0]?.text === undefined);
 229	    const index = isInitialQueryEmpty ? 0 : queriesList.size;
 230	
 231	    // Prevent the same selection from being added consecutively
 232	    const lastQuery = queriesListDetails[queriesListDetails.length - 1];
 233	    if (lastQuery.text === query) {
 234	      return;
 235	    }
 236	
 237	    // Add current query selection to the Redux store which holds the list of queries.
 238	    dispatch(queryBrowserPatchQuery(index, { isEnabled: true, query, text: query }));
 239	  };
 240	
 241	  return (
 242	    <Grid className="predefined-query-select--padding">
 243	      <GridItem>
 244	        <label htmlFor="predefined-query-select-label">{t('Queries')}</label>
 245	      </GridItem>
 246	      <GridItem>
 247	        <TypeaheadSelect
 248	          placeholder={t('Select query')}
 249	          onSelect={insertPredefinedQuery}
 250	          options={queries}
 251	        />
 252	      </GridItem>
 253	    </Grid>
 254	  );
 255	};
