 585	  const [perPage, setPerPage] = React.useState(50);
 586	  const [sortBy, setSortBy] = React.useState<ISortBy>({});
 587	
 588	  const isEnabled = useSelector((state: MonitoringState) =>
 589	    getLegacyObserveState(perspective, state)?.getIn([
