 606	  );
 607	  const query = useSelector((state: MonitoringState) =>
 608	    getLegacyObserveState(perspective, state)?.getIn(['queryBrowser', 'queries', index, 'query']),
 609	  );
 610	  const series = useSelector((state: MonitoringState) =>
