 612	  );
 613	  const span = useSelector((state: MonitoringState) =>
 614	    getLegacyObserveState(perspective, state)?.getIn(['queryBrowser', 'timespan']),
 615	  );
 616	
 617	  const lastRequestTime = useSelector((state: MonitoringState) =>
 618	    getLegacyObserveState(perspective, state)?.getIn(['queryBrowser', 'lastRequestTime']),
 619	  );
 620	
 621	  const dispatch = useDispatch();
 622	
 623	  const toggleAllSeries = React.useCallback(
 624	    () => dispatch(queryBrowserToggleAllSeries(index)),
 625	    [dispatch, index],
 626	  );
 627	
 628	  const isDisabledSeriesEmpty = useSelector((state: MonitoringState) =>
 629	    _.isEmpty(
 630	      getLegacyObserveState(perspective, state)?.getIn([
 631	        'queryBrowser',
