 355	const SeriesButton: React.FC<SeriesButtonProps> = ({ index, labels }) => {
 356	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 357	  const { perspective } = usePerspective();
 358	
 359	  const [colorIndex, isDisabled, isSeriesEmpty] = useSelector((state: MonitoringState) => {
 360	    const observe = getLegacyObserveState(perspective, state);
 361	    const disabledSeries = observe.getIn(['queryBrowser', 'queries', index, 'disabledSeries']);
 362	    if (_.some(disabledSeries, (s) => _.isEqual(s, labels))) {
 363	      return [null, true, false];
 364	    }
 365	
 366	    const series = observe.getIn(['queryBrowser', 'queries', index, 'series']);
 367	    if (_.isEmpty(series)) {
 368	      return [null, false, true];
 369	    }
 370	
 371	    const colorOffset = observe
 372	      .getIn(['queryBrowser', 'queries'])
 373	      .take(index)
 374	      .filter((q) => q.get('isEnabled'))
 375	      .reduce((sum, q) => sum + _.size(q.get('series')), 0);
 376	    const seriesIndex = _.findIndex(series, (s) => _.isEqual(s, labels));
 377	    return [(colorOffset + seriesIndex) % colors.length, false, false];
 378	  });
 379	
 380	  const dispatch = useDispatch();
 381	  const toggleSeries = React.useCallback(
 382	    () => dispatch(queryBrowserToggleSeries(index, labels)),
 383	    [dispatch, index, labels],
 384	  );
 385	
 386	  if (isSeriesEmpty) {
 387	    return <div className="query-browser__series-btn-wrap"></div>;
