 408	const QueryKebab: React.FC<{ index: number }> = ({ index }) => {
 409	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 410	  const { perspective } = usePerspective();
 411	
 412	  const isDisabledSeriesEmpty = useSelector((state: MonitoringState) =>
 413	    _.isEmpty(
 414	      getLegacyObserveState(perspective, state)?.getIn([
 415	        'queryBrowser',
 416	        'queries',
 417	        index,
 418	        'disabledSeries',
 419	      ]),
 420	    ),
 421	  );
 422	  const isEnabled = useSelector((state: MonitoringState) =>
 423	    getLegacyObserveState(perspective, state)?.getIn([
 424	      'queryBrowser',
 425	      'queries',
 426	      index,
 427	      'isEnabled',
 428	    ]),
 429	  );
 430	
 431	  const query = useSelector((state: MonitoringState) =>
 432	    getLegacyObserveState(perspective, state)?.getIn(['queryBrowser', 'queries', index, 'query']),
 433	  );
 434	
 435	  const queryTableData = useSelector((state: MonitoringState) =>
 436	    getLegacyObserveState(perspective, state)?.getIn([
 437	      'queryBrowser',
 438	      'queries',
 439	      index,
 440	      'queryTableData',
 441	    ]),
 442	  );
 443	
 444	  const dispatch = useDispatch();
 445	
 446	  const toggleIsEnabled = React.useCallback(
 447	    () => dispatch(queryBrowserToggleIsEnabled(index)),
 448	    [dispatch, index],
 449	  );
 450	
 451	  const toggleAllSeries = React.useCallback(
 452	    () => dispatch(queryBrowserToggleAllSeries(index)),
 453	    [dispatch, index],
 454	  );
 455	
 456	  const doDelete = React.useCallback(() => {
 457	    dispatch(queryBrowserDeleteQuery(index));
 458	    focusedQuery = undefined;
 459	  }, [dispatch, index]);
 460	
 461	  const doClone = React.useCallback(() => {
 462	    dispatch(queryBrowserDuplicateQuery(index));
 463	  }, [dispatch, index]);
 464	
 465	  const isSpan = (item) => item?.title?.props?.children;
 466	  const getSpanText = (item) => item.title.props.children;
 467	
 468	  // Takes data from QueryTable and removes/replaces all html objects from columns and rows
 469	  const convertQueryTable = () => {
 470	    const getColumns = () => {
 471	      const columns = queryTableData.columns;
 472	      const csvColumnHeaders = columns.slice(1).map((columnHeader) => {
 473	        if (typeof columnHeader?.title === 'string') {
 474	          return columnHeader.title;
 475	        } else if (isSpan(columnHeader)) {
 476	          return getSpanText(columnHeader);
 477	        } else {
 478	          return '';
 479	        }
 480	      });
 481	      return csvColumnHeaders;
 482	    };
 483	    const getRows = () => {
 484	      const rows = queryTableData.rows;
 485	      const csvRows = rows
 486	        .map((row) => row.slice(1))
 487	        .map((row) =>
 488	          row.map((rowItem) => {
 489	            return isSpan(rowItem) ? getSpanText(rowItem) : rowItem;
 490	          }),
 491	        );
 492	      return csvRows;
 493	    };
 494	    const tableData = [getColumns(), ...getRows()];
 495	    return tableData;
 496	  };
 497	
 498	  const getCsv = (array, delimiter = ',') =>
 499	    array
 500	      .map((row) =>
 501	        row.map((rowItem) => (isNaN(rowItem) ? `"${rowItem}"` : rowItem)).join(delimiter),
 502	      )
 503	      .join('\n');
 504	
 505	  const downloadCsv = (csvData) => {
 506	    // Modified from https://codesandbox.io/p/sandbox/react-export-to-csv-l6uhq?file=%2Fsrc%2FApp.jsx%3A39%2C10-39%2C16
 507	    const blob = new Blob([csvData], { type: 'data:text/csv;charset=utf-8,' });
 508	    const blobURL = window.URL.createObjectURL(blob);
 509	    // Create new tag for download file
 510	    const anchor = document.createElement('a');
 511	    anchor.download = `OpenShift_Metrics_QueryTable_${query}.csv`;
 512	    anchor.href = blobURL;
 513	    anchor.dataset.downloadurl = ['text/csv', anchor.download, anchor.href].join(':');
 514	    anchor.click();
 515	    // Remove URL.createObjectURL. The browser should not save the reference to the file.
 516	    setTimeout(() => {
 517	      // For Firefox it is necessary to delay revoking the ObjectURL
 518	      URL.revokeObjectURL(blobURL);
 519	    }, 100);
 520	  };
 521	
 522	  const doExportCsv = () => {
 523	    const tableData = convertQueryTable();
 524	    const csvData = getCsv(tableData);
 525	    downloadCsv(csvData);
 526	  };
 527	
 528	  const exportDropdownItem = (
 529	    <DropdownItem key="export" component="button" onClick={doExportCsv}>
 530	      {t('Export as CSV')}
 531	    </DropdownItem>
 532	  );
 533	
 534	  const defaultDropdownItems = [
 535	    <DropdownItem key="toggle-query" component="button" onClick={toggleIsEnabled}>
 536	      {isEnabled ? t('Disable query') : t('Enable query')}
 537	    </DropdownItem>,
 538	    isEnabled ? (
 539	      <DropdownItem component="button" onClick={toggleAllSeries} key="toggle-all-series">
 540	        {isDisabledSeriesEmpty ? t('Hide all series') : t('Show all series')}
 541	      </DropdownItem>
 542	    ) : (
 543	      <Tooltip
 544	        key="toggle-all-series-disabled"
 545	        position="left"
 546	        content={t('Query must be enabled')}
 547	      >
 548	        <DropdownItem
 549	          isAriaDisabled={true} // need to receive focus for tooltip to work
 550	          component="button"
 551	        >
 552	          {isDisabledSeriesEmpty ? t('Hide all series') : t('Show all series')}
 553	        </DropdownItem>
 554	      </Tooltip>
 555	    ),
 556	    <DropdownItem key="delete" component="button" onClick={doDelete}>
 557	      {t('Delete query')}
 558	    </DropdownItem>,
 559	    <DropdownItem key="duplicate" component="button" onClick={doClone}>
 560	      {t('Duplicate query')}
 561	    </DropdownItem>,
 562	  ];
 563	
 564	  const hasQueryTableData = () => {
 565	    if (!query || !queryTableData?.rows || !queryTableData?.columns) {
 566	      return false;
 567	    }
 568	    return true;
 569	  };
 570	
 571	  const dropdownItems = hasQueryTableData()
 572	    ? [...defaultDropdownItems, exportDropdownItem]
 573	    : defaultDropdownItems;
 574	
 575	  return <KebabDropdown dropdownItems={dropdownItems} />;
 576	};
