 639	  // eslint-disable-next-line react-hooks/exhaustive-deps
 640	  const safeFetch = React.useCallback(useSafeFetch(), []);
 641	
 642	  // If the namespace is defined getPrometheusURL will use
 643	  // the PROMETHEUS_TENANCY_BASE_PATH for requests in the developer view
 644	  const tick = () => {
 645	    if (isEnabled && isExpanded && query) {
 646	      safeFetch(
 647	        getPrometheusURL(
 648	          {
 649	            endpoint: PrometheusEndpoint.QUERY,
 650	            namespace: perspective === 'dev' ? namespace : '',
 651	            query,
 652	          },
 653	          perspective,
 654	          customDatasource?.basePath,
 655	        ),
 656	      )
 657	        .then((response) => {
 658	          setData(_.get(response, 'data'));
 659	          setError(undefined);
 660	        })
 661	        .catch((err) => {
 662	          if (err.name !== 'AbortError') {
 663	            setData(undefined);
 664	            setError(err);
 665	          }
 666	        });
 667	    }
 668	  };
 669	
 670	  usePoll(tick, pollInterval, namespace, query, span, lastRequestTime);
 671	
 672	  React.useEffect(() => {
 673	    setData(undefined);
 674	    setError(undefined);
 675	    setPage(1);
 676	    setSortBy({});
 677	  }, [namespace, query]);
 678	
 679	  if (!isEnabled || !isExpanded || !query) {
