 701	  // point during the graph's range.
 702	  const expiredSeries = _.differenceWith(series, data.result, (s, r) => _.isEqual(s, r.metric));
 703	  const result = expiredSeries.length
 704	    ? [...data.result, ...expiredSeries.map((metric) => ({ metric }))]
